public JsonToken nextToken() throws IOException, JsonParseException
{
    JsonToken t;

    // If this is the first call and the delegate has a current token, return it first
    if (!_initialized) {
        t = delegate.getCurrentToken();
        if (t != null) {
            _initialized = true;
            return t;
        }
        _initialized = true; // Mark as initialized even if no current token
    }

    // After initialization, advance to next token
    t = delegate.nextToken();
    if (t != null) return t;

    // If that was null, try switching to next parser
    while (switchToNext()) {
        _initialized = false; // Reset for the new delegate
        t = delegate.getCurrentToken();
        if (t != null) {
            _initialized = true;
            return t;
        }
        _initialized = true; // Mark as initialized
        t = delegate.nextToken();
        if (t != null) return t;
    }
